import ldap
from ldap.controls import SimplePagedResultsControl

def search_user(username, base_dn):
    conn = ldap.initialize('ldaps://ldap.example.com')  # Replace with your LDAP server URL
    conn.set_option(ldap.OPT_REFERRALS, 0)
    
    try:
        conn.simple_bind_s('username', 'password')  # Replace with your LDAP username and password
        
        controls = [SimplePagedResultsControl(size=10, criticality=False)]
        result = conn.search_ext(base_dn, ldap.SCOPE_SUBTREE, f'(uid={username})', None, controls)
        
        if result:
            type_, data = next(iter(result))
            
            if type_ == "sr":
                for item in data['items']:
                    print('DN:', item[0])  # Print DN of found user
                    
    except ldap.LDAPError as e:
        print(e)
        
